const fs = require('fs');
const path = 'c:/projetos/iVan/09_MVP_Concierge/code/CadastroWebApp.html';

let html = fs.readFileSync(path, 'utf8');

// 1. Substituir o interior do fields-parent
const fieldsParentRegex = /<div id="fields-parent" style="display: none;">[\s\S]*?<!-- CAMPOS EXCLUSIVOS MOTORISTA -->/;
const fieldsParentNew = `<div id="fields-parent" style="display: none;">
          <div id="alunos-cards-container">
            <!-- Cards de alunos adicionados dinamicamente -->
          </div>
          <button type="button" class="btn btn-secondary" onclick="adicionarCardAluno()" style="margin-top: 15px; margin-bottom: 20px; width: 100%; border: 1px dashed var(--primary); color: var(--primary); background: transparent;">
            ➕ Adicionar Outro Aluno
          </button>
        </div>

        <!-- CAMPOS EXCLUSIVOS MOTORISTA -->`;
html = html.replace(fieldsParentRegex, fieldsParentNew);

// 2. Adicionar as funções de manipulação de cards, e buscarDadosPorTelefone
const funcAddText = `
    let countAlunos = 0;

    function adicionarCardAluno(alunoData = null) {
      countAlunos++;
      const id = countAlunos;
      const container = document.getElementById("alunos-cards-container");

      const card = document.createElement("div");
      card.className = "aluno-card";
      card.id = "aluno-card-" + id;
      card.style.cssText = "border: 1px solid var(--border); border-radius: 8px; padding: 15px; margin-bottom: 15px; background-color: var(--card-bg); position: relative;";

      let htmlCard = \`
        <button type="button" onclick="removerCardAluno(\${id})" style="position: absolute; top: 10px; right: 10px; background: transparent; border: none; color: var(--error); font-size: 20px; cursor: pointer; display: \${countAlunos > 1 ? 'block' : 'none'};">&times;</button>
        <h4 style="margin-top: 0; color: var(--primary); font-size: 15px; margin-bottom: 15px;">Dados do Aluno <span class="aluno-num">\${id}</span></h4>
        <input type="hidden" id="p-aluno-editId-\${id}">

        <div class="form-group">
          <label for="p-nome-aluno-\${id}">NOME DO ALUNO</label>
          <input type="text" id="p-nome-aluno-\${id}" class="aluno-field-nome" placeholder="Nome completo do estudante">
          <div class="error-msg" id="p-nome-aluno-error-\${id}">Preencha o nome completo (mín. 8 caracteres).</div>
        </div>
        <div class="form-group">
          <label for="p-doc-aluno-\${id}">DOCUMENTO DO ALUNO (CPF, RG OU CERTIDÃO)</label>
          <input type="text" id="p-doc-aluno-\${id}" class="aluno-field-doc" placeholder="Apenas números">
          <div class="error-msg" id="p-doc-aluno-error-\${id}">Documento inválido.</div>
        </div>
        <div class="form-group">
          <label for="p-cidade-\${id}">CIDADE / UF</label>
          <select id="p-cidade-\${id}" class="aluno-field-cidade" onchange="filtrarEscolasDropdownIdx(\${id})">
            <option value="">Selecione a cidade...</option>
          </select>
        </div>
        <div class="form-group">
          <label for="p-escola-\${id}">ESCOLA (DESTINO)</label>
          <select id="p-escola-\${id}" class="aluno-field-escola" onchange="carregarMotoristasCompativeisIdx(\${id})">
            <option value="">Selecione a escola...</option>
          </select>
          <div class="error-msg" id="p-escola-error-\${id}">Selecione uma escola.</div>
        </div>
        <div class="form-group">
          <label for="p-turno-\${id}">TURNO DO TRANSPORTE</label>
          <select id="p-turno-\${id}" class="aluno-field-turno" onchange="carregarMotoristasCompativeisIdx(\${id})">
            <option value="">Selecione o turno...</option>
            <option value="Manhã">Manhã</option>
            <option value="Tarde">Tarde</option>
            <option value="Noite">Noite</option>
            <option value="Integral">Integral</option>
          </select>
          <div class="error-msg" id="p-turno-error-\${id}">Selecione o turno.</div>
        </div>
        <div class="form-group">
          <label for="p-motorista-\${id}">MOTORISTA PRETENDIDO (OPCIONAL)</label>
          <select id="p-motorista-\${id}" class="aluno-field-motorista">
            <option value="">Selecione o motorista...</option>
          </select>
        </div>
        <div class="form-group">
          <label for="p-endereco-\${id}">ENDEREÇO DE BUSCA (OPCIONAL)</label>
          <textarea id="p-endereco-\${id}" class="aluno-field-endereco" rows="2" placeholder="Rua, Número, Bairro, Cidade"></textarea>
          <input type="hidden" id="p-latitude-\${id}" class="aluno-field-lat">
          <input type="hidden" id="p-longitude-\${id}" class="aluno-field-lng">
          <button type="button" class="geo-btn" onclick="capturarLocalizacaoIdx(\${id})">
            📍 Preencher com minha localização atual
          </button>
        </div>
        <div class="form-group" style="margin-bottom:0;">
          <label for="p-contato-sec-\${id}">CONTATO DE EMERGÊNCIA SEC. (OPCIONAL)</label>
          <input type="text" id="p-contato-sec-\${id}" class="aluno-field-contato" placeholder="Nome e Telefone">
        </div>
      \`;
      card.innerHTML = htmlCard;
      container.appendChild(card);

      atualizarBotoesRemover();

      // Preencher select de cidades
      const selectCidade = document.getElementById(\`p-cidade-\${id}\`);
      cidadesUnicas.forEach(c => {
        const opt = document.createElement("option");
        opt.value = c; opt.innerText = c;
        selectCidade.appendChild(opt);
      });

      // Popular dropdown escolas inicial
      filtrarEscolasDropdownIdx(id);

      if (alunoData) {
        document.getElementById(\`p-aluno-editId-\${id}\`).value = alunoData.id || "";
        document.getElementById(\`p-nome-aluno-\${id}\`).value = alunoData.nome || "";
        document.getElementById(\`p-doc-aluno-\${id}\`).value = alunoData.documentoAluno || "";
        document.getElementById(\`p-endereco-\${id}\`).value = alunoData.enderecoBusca || "";
        document.getElementById(\`p-latitude-\${id}\`).value = alunoData.latitude || "";
        document.getElementById(\`p-longitude-\${id}\`).value = alunoData.longitude || "";
        document.getElementById(\`p-contato-sec-\${id}\`).value = alunoData.contatoSecundario || "";

        const escSelect = document.getElementById(\`p-escola-\${id}\`);
        Array.from(escSelect.options).forEach(opt => {
          if (opt.value === alunoData.escola) opt.selected = true;
        });

        const shiftSelect = document.getElementById(\`p-turno-\${id}\`);
        Array.from(shiftSelect.options).forEach(opt => {
          if (opt.value === alunoData.turno) opt.selected = true;
        });

        carregarMotoristasCompativeisIdx(id, alunoData.motoristaPretendido);
      }
    }

    function removerCardAluno(id) {
      const card = document.getElementById("aluno-card-" + id);
      if (card) {
        card.remove();
        atualizarBotoesRemover();
      }
    }

    function atualizarBotoesRemover() {
      const cards = document.querySelectorAll(".aluno-card");
      cards.forEach((card, index) => {
        card.querySelector(".aluno-num").innerText = index + 1;
        const btn = card.querySelector("button");
        if (cards.length > 1) {
          btn.style.display = "block";
        } else {
          btn.style.display = "none";
        }
      });
    }

    function filtrarEscolasDropdownIdx(id) {
      const select = document.getElementById(\`p-escola-\${id}\`);
      const filterCidade = document.getElementById(\`p-cidade-\${id}\`).value;

      select.innerHTML = '<option value="">Selecione a escola...</option>';
      escolasCadastradas.forEach(esc => {
        if (!filterCidade || esc.cidadeUf === filterCidade) {
          const opt = document.createElement("option");
          opt.value = esc.nome;
          opt.innerText = esc.nome;
          if (querySchool && esc.nome.toLowerCase() === querySchool.toLowerCase()) {
            opt.selected = true;
          }
          select.appendChild(opt);
        }
      });

      if (queryShift) {
        const selectShift = document.getElementById(\`p-turno-\${id}\`);
        for (let i = 0; i < selectShift.options.length; i++) {
          if (selectShift.options[i].value.toLowerCase() === queryShift.toLowerCase()) {
            selectShift.options[i].selected = true;
            break;
          }
        }
      }
      carregarMotoristasCompativeisIdx(id);
    }

    function carregarMotoristasCompativeisIdx(id, selectedMot = null) {
      if (userProfile !== "parent") return;
      const schoolVal = document.getElementById(\`p-escola-\${id}\`).value;
      const shiftVal = document.getElementById(\`p-turno-\${id}\`).value;
      const selectMot = document.getElementById(\`p-motorista-\${id}\`);

      selectMot.innerHTML = '<option value="">Carregando motoristas...</option>';

      if (!schoolVal || !shiftVal) {
        selectMot.innerHTML = '<option value="">Selecione Escola e Turno primeiro</option>';
        return;
      }

      google.script.run.withSuccessHandler(function(motoristas) {
        selectMot.innerHTML = '<option value="">Selecione o motorista...</option>';
        if (motoristas.length === 0) {
          const opt = document.createElement("option");
          opt.value = "";
          opt.innerText = "Nenhum motorista disponível";
          selectMot.appendChild(opt);
          return;
        }
        motoristas.forEach(mot => {
          const opt = document.createElement("option");
          opt.value = mot.nome;
          opt.innerText = mot.nome;
          if (selectedMot && mot.nome === selectedMot) opt.selected = true;
          selectMot.appendChild(opt);
        });
      }).getMotoristasPorEscolaETurno(schoolVal, shiftVal);
    }

    function capturarLocalizacaoIdx(id) {
      const btn = document.querySelector(\`#aluno-card-\${id} .geo-btn\`);
      const textarea = document.getElementById(\`p-endereco-\${id}\`);
      const latInput = document.getElementById(\`p-latitude-\${id}\`);
      const lngInput = document.getElementById(\`p-longitude-\${id}\`);

      btn.innerText = "⌛ Acessando localização...";

      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          function(position) {
            const lat = position.coords.latitude;
            const lng = position.coords.longitude;
            latInput.value = lat;
            lngInput.value = lng;
            textarea.value = "Parada Georreferenciada (Lat: " + lat.toFixed(5) + ", Lng: " + lng.toFixed(5) + ")";
            btn.innerText = "✅ Localização Capturada!";
          },
          function(error) {
            btn.innerText = "❌ Permissão Negada ou Falha";
            setTimeout(() => { btn.innerText = "📍 Preencher com minha localização atual"; }, 3000);
          },
          { enableHighAccuracy: true, timeout: 5000 }
        );
      } else {
        btn.innerText = "❌ Não suportado pelo navegador";
      }
    }

    function buscarDadosPorTelefone() {
      const telInput = document.getElementById("tel-search");
      const telVal = telInput.value;
      if (!regexPhone.test(telVal)) return;
      if (typeof google === 'undefined') return;

      telInput.disabled = true;
      google.script.run
        .withSuccessHandler(function(result) {
          telInput.disabled = false;
          if (result) {
            if (userProfile === "driver" && result.placa) {
              editModeId = result.id;
              document.getElementById("d-nome").value = result.nome;
              document.getElementById("doc-search").value = result.documento || "";
              document.getElementById("d-placa").value = result.placa;
              const checkboxes = document.getElementsByName("d-escolas");
              checkboxes.forEach(cb => {
                if (result.escolas.indexOf(cb.value) !== -1) cb.checked = true;
              });
            } else if (userProfile === "parent" && result.responsavel) {
              editModeId = result.responsavel.id;
              document.getElementById("p-nome-resp").value = result.responsavel.nome;
              document.getElementById("doc-search").value = result.responsavel.documento || "";
              if (result.alunos && result.alunos.length > 0) {
                 window.loadedAlunos = result.alunos;
              }
            }
          }
        })
        .withFailureHandler(function(err) {
          telInput.disabled = false;
        })
        .buscarCadastroPorDocumento("", telVal, userProfile);
    }
`;

html = html.replace('function verificarIdentificacao() {', funcAddText + '\n    function verificarIdentificacao() {');

// 3. Atualizar verificarIdentificacao para renderizar os cards corretamente
const vfRegex = /if \(userProfile === "parent" && result\.responsavel\) \{[\s\S]*?\}\s*\}\s*\}\s*mostrarPasso\(2\);/g;
html = html.replace(vfRegex, `if (userProfile === "parent" && result.responsavel) {
                editModeId = result.responsavel.id;
                document.getElementById("p-nome-resp").value = result.responsavel.nome;
                if (result.alunos && result.alunos.length > 0) {
                   window.loadedAlunos = result.alunos;
                }
              }
            }
            // Múltiplos alunos
            if (userProfile === "parent") {
               const container = document.getElementById("alunos-cards-container");
               container.innerHTML = "";
               countAlunos = 0;
               if (window.loadedAlunos && window.loadedAlunos.length > 0) {
                 window.loadedAlunos.forEach(al => adicionarCardAluno(al));
               } else {
                 adicionarCardAluno();
               }
            }
            mostrarPasso(2);`);

// 4. Atualizar revisarDados
const revDataRegex = /const nomeAlunoInput = document\.getElementById\("p-nome-aluno"\);[\s\S]*?if \(hasError\) \{/g;
const revDataNew = `
        const cards = document.querySelectorAll(".aluno-card");
        cards.forEach(card => {
          const id = card.id.split('-').pop();
          const nomeAlunoInput = document.getElementById("p-nome-aluno-" + id);
          const docAlunoInput = document.getElementById("p-doc-aluno-" + id);
          const escolaInput = document.getElementById("p-escola-" + id);
          const turnoInput = document.getElementById("p-turno-" + id);

          if (nomeAlunoInput.value.trim().length < 8) {
            nomeAlunoInput.style.borderColor = "var(--error)";
            document.getElementById("p-nome-aluno-error-" + id).style.display = "block";
            hasError = true;
          } else {
            nomeAlunoInput.style.borderColor = "var(--border)";
            document.getElementById("p-nome-aluno-error-" + id).style.display = "none";
          }

          const docAlunoVal = docAlunoInput.value.replace(/\\D/g, "");
          if (!regexDoc.test(docAlunoVal)) {
            docAlunoInput.style.borderColor = "var(--error)";
            document.getElementById("p-doc-aluno-error-" + id).style.display = "block";
            hasError = true;
          } else {
            docAlunoInput.style.borderColor = "var(--border)";
            document.getElementById("p-doc-aluno-error-" + id).style.display = "none";
          }

          if (!escolaInput.value) {
            escolaInput.style.borderColor = "var(--error)";
            document.getElementById("p-escola-error-" + id).style.display = "block";
            hasError = true;
          } else {
            escolaInput.style.borderColor = "var(--border)";
            document.getElementById("p-escola-error-" + id).style.display = "none";
          }

          if (!turnoInput.value) {
            turnoInput.style.borderColor = "var(--error)";
            document.getElementById("p-turno-error-" + id).style.display = "block";
            hasError = true;
          } else {
            turnoInput.style.borderColor = "var(--border)";
            document.getElementById("p-turno-error-" + id).style.display = "none";
          }
        });

        if (hasError) {`;
html = html.replace(revDataRegex, revDataNew);

// 5. Atualizar resumo em revisarDados
const sumRegex = /const nomeAluno = document\.getElementById\("p-nome-aluno"\)\.value;[\s\S]*?\}\s*\}/g;
const sumNew = `
        html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">RESPONSÁVEL</span><span class=\\"summary-value\\">" + nomeResp + "</span></div>";
        html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">TELEFONE RESPONSÁVEL</span><span class=\\"summary-value\\">" + telVal + "</span></div>";
        html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">DOCUMENTO RESPONSÁVEL</span><span class=\\"summary-value\\">" + docVal + "</span></div>";

        const cards = document.querySelectorAll(".aluno-card");
        cards.forEach((card, idx) => {
          const id = card.id.split('-').pop();
          const nomeAluno = document.getElementById("p-nome-aluno-" + id).value;
          const docAluno = document.getElementById("p-doc-aluno-" + id).value;
          const escola = document.getElementById("p-escola-" + id).value;
          const turno = document.getElementById("p-turno-" + id).value;
          const motorista = document.getElementById("p-motorista-" + id).value;
          const endereco = document.getElementById("p-endereco-" + id).value;

          html += "<hr style=\\"border-color: var(--border); margin: 15px 0;\\">";
          html += "<div class=\\"summary-item\\" style=\\"color: var(--primary); font-weight: bold;\\">Aluno " + (idx+1) + "</div>";
          html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">NOME DO ALUNO</span><span class=\\"summary-value\\">" + nomeAluno + "</span></div>";
          html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">DOCUMENTO</span><span class=\\"summary-value\\">" + docAluno + "</span></div>";
          html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">ESCOLA / TURNO</span><span class=\\"summary-value\\">" + escola + " (" + turno + ")</span></div>";
          if (motorista) html += "<div class=\\"summary-item\\"><span class=\\"summary-label\\">MOTORISTA PRETENDIDO</span><span class=\\"summary-value\\">" + motorista + "</span></div>";
        });
      }`;
html = html.replace(sumRegex, sumNew);

// 6. Atualizar confirmarSalvar para enviar payload.alunos
const saveRegex = /payload\.nomeAluno = document\.getElementById\("p-nome-aluno"\)\.value;[\s\S]*?payload\.contatoSecundario = document\.getElementById\("p-contato-sec"\)\.value;/g;
const saveNew = `payload.nomeResponsavel = document.getElementById("p-nome-resp").value;
        payload.alunos = [];
        const cards = document.querySelectorAll(".aluno-card");
        cards.forEach(card => {
          const id = card.id.split('-').pop();
          payload.alunos.push({
            editIdAluno: document.getElementById("p-aluno-editId-" + id).value,
            nomeAluno: document.getElementById("p-nome-aluno-" + id).value,
            documentoAluno: document.getElementById("p-doc-aluno-" + id).value,
            escola: document.getElementById("p-escola-" + id).value,
            turno: document.getElementById("p-turno-" + id).value,
            motoristaPretendido: document.getElementById("p-motorista-" + id).value,
            enderecoBusca: document.getElementById("p-endereco-" + id).value,
            latitude: document.getElementById("p-latitude-" + id).value,
            longitude: document.getElementById("p-longitude-" + id).value,
            contatoSecundario: document.getElementById("p-contato-sec-" + id).value
          });
        });`;
html = html.replace(saveRegex, saveNew);

// 7. Remover popularCidades e outros obsoletos soltos se tiver
html = html.replace(/function popularCidades\(\) \{[\s\S]*?\}\n/g, '');
html = html.replace(/function popularEscolasDropdown\(\) \{[\s\S]*?\}\n/g, '');
html = html.replace(/function filtrarEscolasDropdown\(\) \{[\s\S]*?\}\n/g, '');
html = html.replace(/function carregarMotoristasCompativeis\(\) \{[\s\S]*?\}\n/g, '');
html = html.replace(/function capturarLocalizacao\(\) \{[\s\S]*?\}\n/g, '');

fs.writeFileSync(path, html, 'utf8');
console.log("WebApp patch applied.");

const fs = require('fs');
const path = 'c:/projetos/iVan/09_MVP_Concierge/code/CadastroWebApp.html';

let html = fs.readFileSync(path, 'utf8');

// The corrupted block is between:
//     // --- FUNÇÃO NOVO: RESPONSÁVEL É O PRÓPRIO ALUNO ---
// and
//       const summary = document.getElementById("summary-content");

const startMarker = "    // --- FUNÇÃO NOVO: RESPONSÁVEL É O PRÓPRIO ALUNO ---";
const endMarker = "      const summary = document.getElementById(\"summary-content\");";

const startIndex = html.indexOf(startMarker);
const endIndex = html.indexOf(endMarker);

if (startIndex !== -1 && endIndex !== -1) {
  const replacement = `    // --- FUNÇÃO NOVO: RESPONSÁVEL É O PRÓPRIO ALUNO ---
    function toggleRespIsAluno() {
      const isChecked = document.getElementById("resp-is-aluno").checked;
      const respNameInput = document.getElementById("p-nome-resp");
      const respDocInput = document.getElementById("doc-search");

      const cards = document.querySelectorAll(".aluno-card");
      if (cards.length > 0) {
        const firstCardId = cards[0].id.split('-').pop();
        const nomeAlunoInput = document.getElementById("p-nome-aluno-" + firstCardId);
        const docAlunoInput = document.getElementById("p-doc-aluno-" + firstCardId);

        if (isChecked) {
          nomeAlunoInput.value = respNameInput.value;
          docAlunoInput.value = respDocInput.value;
          nomeAlunoInput.readOnly = true;
          docAlunoInput.readOnly = true;
          nomeAlunoInput.style.backgroundColor = "var(--border)";
          docAlunoInput.style.backgroundColor = "var(--border)";
        } else {
          nomeAlunoInput.value = "";
          docAlunoInput.value = "";
          nomeAlunoInput.readOnly = false;
          docAlunoInput.readOnly = false;
          nomeAlunoInput.style.backgroundColor = "var(--input-bg)";
          docAlunoInput.style.backgroundColor = "var(--input-bg)";
        }
      }
    }

    let countAlunos = 0;

    function adicionarCardAluno(alunoData = null) {
      countAlunos++;
      const id = countAlunos;
      const container = document.getElementById("alunos-cards-container");

      const card = document.createElement("div");
      card.className = "aluno-card";
      card.id = "aluno-card-" + id;
      card.style.cssText = "border: 1px solid var(--border); border-radius: 8px; padding: 15px; margin-bottom: 15px; background-color: var(--card-bg); position: relative;";

      let htmlCard = \`
        <button type="button" onclick="removerCardAluno(\${id})" style="position: absolute; top: 10px; right: 10px; background: transparent; border: none; color: var(--error); font-size: 20px; cursor: pointer; display: \${countAlunos > 1 ? 'block' : 'none'};">&times;</button>
        <h4 style="margin-top: 0; color: var(--primary); font-size: 15px; margin-bottom: 15px;">Dados do Aluno <span class="aluno-num">\${id}</span></h4>
        <input type="hidden" id="p-aluno-editId-\${id}">

        <div class="form-group">
          <label for="p-nome-aluno-\${id}">NOME DO ALUNO</label>
          <input type="text" id="p-nome-aluno-\${id}" class="aluno-field-nome" placeholder="Nome completo do estudante">
          <div class="error-msg" id="p-nome-aluno-error-\${id}">Preencha o nome completo (mín. 8 caracteres).</div>
        </div>
        <div class="form-group">
          <label for="p-doc-aluno-\${id}">DOCUMENTO DO ALUNO (CPF, RG OU CERTIDÃO)</label>
          <input type="text" id="p-doc-aluno-\${id}" class="aluno-field-doc" placeholder="Apenas números">
          <div class="error-msg" id="p-doc-aluno-error-\${id}">Documento inválido.</div>
        </div>
        <div class="form-group">
          <label for="p-cidade-\${id}">CIDADE / UF</label>
          <select id="p-cidade-\${id}" class="aluno-field-cidade" onchange="filtrarEscolasDropdownIdx(\${id})">
            <option value="">Selecione a cidade...</option>
          </select>
        </div>
        <div class="form-group">
          <label for="p-escola-\${id}">ESCOLA (DESTINO)</label>
          <select id="p-escola-\${id}" class="aluno-field-escola" onchange="carregarMotoristasCompativeisIdx(\${id})">
            <option value="">Selecione a escola...</option>
          </select>
          <div class="error-msg" id="p-escola-error-\${id}">Selecione uma escola.</div>
        </div>
        <div class="form-group">
          <label for="p-turno-\${id}">TURNO DO TRANSPORTE</label>
          <select id="p-turno-\${id}" class="aluno-field-turno" onchange="carregarMotoristasCompativeisIdx(\${id})">
            <option value="">Selecione o turno...</option>
            <option value="Manhã">Manhã</option>
            <option value="Tarde">Tarde</option>
            <option value="Noite">Noite</option>
            <option value="Integral">Integral</option>
          </select>
          <div class="error-msg" id="p-turno-error-\${id}">Selecione o turno.</div>
        </div>
        <div class="form-group">
          <label for="p-motorista-\${id}">MOTORISTA PRETENDIDO (OPCIONAL)</label>
