              editModeId = result.responsavel.id;
              document.getElementById("p-nome-resp").value = result.responsavel.nome;
              document.getElementById("doc-search").value = result.responsavel.documento || "";
              if (result.alunos && result.alunos.length > 0) {
                 window.loadedAlunos = result.alunos;
              }
            }
          }
        })
        .withFailureHandler(function(err) {
          telInput.disabled = false;
        })
        .buscarCadastroPorDocumento("", telVal, userProfile);
    }

    function verificarIdentificacao() {
      try {
        const docInput = document.getElementById("doc-search");
        const telInput = document.getElementById("tel-search");

        const docVal = docInput.value.replace(/\\D/g, "");
        const telVal = telInput.value;

        let hasError = false;

        if (!regexDoc.test(docVal)) {
          document.getElementById("doc-search-error").style.display = "block";
          hasError = true;
        } else {
          document.getElementById("doc-search-error").style.display = "none";
        }

        if (!regexPhone.test(telVal)) {
          document.getElementById("tel-search-error").style.display = "block";
          hasError = true;
        } else {
          document.getElementById("tel-search-error").style.display = "none";
        }

        if (userProfile === "parent") {
          const respNameInput = document.getElementById("p-nome-resp");
          if (respNameInput.value.trim().length < 8) {
            document.getElementById("p-nome-resp-error").style.display = "block";
            hasError = true;
          } else {
            document.getElementById("p-nome-resp-error").style.display = "none";
          }
        }

        if (hasError) return;

        // Força a cópia dos dados caso o checkbox esteja marcado antes de ir para o painel 2
        toggleRespIsAluno();

        // Loader visual
        docInput.disabled = true;
        telInput.disabled = true;
        if (userProfile === "parent") {
          document.getElementById("p-nome-resp").disabled = true;
        }

        const btn = document.querySelector("#panel-1 .btn-primary");
        const oldBtnText = btn.innerText;
        btn.innerText = "Aguarde...";
        btn.disabled = true;

        const restoreInputs = () => {
          docInput.disabled = false;
          telInput.disabled = false;
          if (userProfile === "parent") {
            document.getElementById("p-nome-resp").disabled = false;
          }
          btn.innerText = oldBtnText;
          btn.disabled = false;
        };

        if (typeof google === 'undefined') {
          console.warn("Executando em modo local (sem servidor).");
          setTimeout(() => {
            restoreInputs();
            if (userProfile === "parent") {
               const container = document.getElementById("alunos-cards-container");
               container.innerHTML = "";
               countAlunos = 0;
               if (window.loadedAlunos && window.loadedAlunos.length > 0) {
                 window.loadedAlunos.forEach(al => adicionarCardAluno(al));
               } else {
                 adicionarCardAluno();
               }
            }
            mostrarPasso(2);
          }, 800);
          return;
        }

        google.script.run
          .withSuccessHandler(function(result) {
            restoreInputs();
            if (result) {
              if (userProfile === "driver" && result.placa) {
                editModeId = result.id;
                document.getElementById("d-nome").value = result.nome;
                document.getElementById("d-placa").value = result.placa;
                const checkboxes = document.getElementsByName("d-escolas");
                checkboxes.forEach(cb => {
                  if (result.escolas.indexOf(cb.value) !== -1) cb.checked = true;
                });
              } else if (userProfile === "parent" && result.responsavel) {
                editModeId = result.responsavel.id;
