      <td style="width: 80px;"><a href="#" class="wi-drill-link" data-id="${a.id}">#${a.id}</a></td>
      <td style="font-weight: 600; max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${a.title}">${a.title}</td>
