function renderTaskActivityDonut(filteredWIs) {
  const container = document.getElementById('chart-capacity-task-activities');
  container.innerHTML = '';

  const activities = {};
  let totalTasks = 0;

  filteredWIs.forEach(wi => {
    const tasks = g_data.tasksByParent.get(wi.Id) || [];
    tasks.forEach(t => {
      // If person filter is active, skip tasks not assigned to this person
      if (g_capacityActivePersonFilter) {
        const resp = t.Responsavel ? t.Responsavel.trim() : '';
        if (resp !== g_capacityActivePersonFilter) return;
      }

      const act = getNormalizedActivity(t.Activity);
      activities[act] = (activities[act] || 0) + 1;
      totalTasks++;
    });
  });

  if (totalTasks === 0) {
    container.innerHTML = `<span class="placeholder-text">Os itens selecionados não possuem subtasks filhas</span>`;
    return;
  }

  const sortedActivities = Object.keys(activities).map(act => ({ label: act, count: activities[act] }))
                                 .sort((a, b) => b.count - a.count);

  const radius = 70;
  const circ = 2 * Math.PI * radius; // ~439.82

  let currentOffset = 0;
  let segments = '';

  sortedActivities.forEach((act, idx) => {
    const col = getActivityColor(act.label);
    const pct = act.count / totalTasks;
    const dashArrayVal = pct * circ;
    const strokeDash = `${dashArrayVal} ${circ - dashArrayVal}`;
    const strokeOffset = -currentOffset;

    const isSelected = g_capacityActiveActivityFilter === act.label;
    const isDimmed = g_capacityActiveActivityFilter && g_capacityActiveActivityFilter !== act.label;

    let segmentClass = "donut-segment capacity-donut-segment";
    if (isSelected) segmentClass += " active";
    if (isDimmed) segmentClass += " inactive";

    const strokeWidth = isSelected ? 20 : 14;
    const opacity = isDimmed ? 0.35 : 1;

    segments += `
      <circle cx="100" cy="100" r="${radius}" fill="none" stroke="${col}" stroke-width="${strokeWidth}" 
              stroke-dasharray="${strokeDash}" stroke-dashoffset="${strokeOffset}" 
              transform="rotate(-90, 100, 100)" class="${segmentClass}" 
              data-activity="${act.label}"
              style="opacity: ${opacity};"/>
    `;
    currentOffset += dashArrayVal;
  });

  // Build detailed Legend
  let legendHtml = '';
  sortedActivities.forEach((act, idx) => {
    const col = getActivityColor(act.label);
    const pct = ((act.count / totalTasks) * 100).toFixed(0);

    const isSelected = g_capacityActiveActivityFilter === act.label;
    const isDimmed = g_capacityActiveActivityFilter && g_capacityActiveActivityFilter !== act.label;
    const opacity = isDimmed ? 'opacity: 0.35;' : 'opacity: 1;';
    const bgHighlight = isSelected ? 'background-color: hsla(252, 31%, 15%, 0.6); border: 1px solid var(--border-color); border-radius: 4px; padding: 2px 6px;' : 'padding: 2px 6px; border: 1px solid transparent;';

    legendHtml += `
      <div class="legend-item capacity-donut-legend" data-activity="${act.label}" style="font-size: 0.8rem; margin-bottom: 6px; cursor: pointer; display: flex; align-items: center; gap: 6px; transition: all var(--transition-smooth); ${bgHighlight} ${opacity}">
        <span class="legend-bullet" style="background-color: ${col}; width: 10px; height: 10px; border-radius: 2px; flex-shrink: 0;"></span>
        <span><strong>${act.label}:</strong> ${act.count} (${pct}%)</span>
      </div>
    `;
  });

  container.innerHTML = `
    <div style="display: flex; align-items: center; justify-content: space-between; width: 100%; height: 100%; padding: 10px 15px; box-sizing: border-box; gap: 20px;">
      <div style="position: relative; width: 200px; height: 200px; flex-shrink: 0; display: flex; align-items: center; justify-content: center;">
        <svg width="200" height="200" viewBox="0 0 200 200" style="display: block;">
          ${segments}
          <!-- Inner Glow Circle -->
          <circle cx="100" cy="100" r="54" fill="var(--bg-main)" stroke="var(--border-color)" stroke-width="1"/>
          <text x="100" y="96" fill="#fff" font-size="24" font-weight="800" text-anchor="middle">${totalTasks}</text>
          <text x="100" y="112" fill="var(--text-muted)" font-size="9" text-anchor="middle" letter-spacing="0.5" style="text-transform: uppercase;">Tasks Filhas</text>
        </svg>
      </div>
      <div style="display: flex; flex-direction: column; justify-content: center; text-align: left; max-height: 240px; overflow-y: auto; padding-right: 5px; flex-grow: 1;">
        ${legendHtml}
      </div>
    </div>
  `;

  // Add Event Listeners for Donut Segments
  container.querySelectorAll('.capacity-donut-segment').forEach(seg => {
    seg.addEventListener('click', () => {
      const actName = seg.getAttribute('data-activity');
      g_capacityActiveActivityFilter = (g_capacityActiveActivityFilter === actName) ? null : actName;
      renderActivePage();
    });
  });

  // Add Event Listeners for Legend Items
  container.querySelectorAll('.capacity-donut-legend').forEach(leg => {
    leg.addEventListener('click', () => {
      const actName = leg.getAttribute('data-activity');
      g_capacityActiveActivityFilter = (g_capacityActiveActivityFilter === actName) ? null : actName;
      renderActivePage();
    });
  });
}

