/**
 * Renderiza o gráfico Donut de Origem de Bugs (Tags da Squad: Legado, !BUG, GeradoPorUS)
 */
function renderBugsOriginDonutChart(bugs) {
  const container = document.getElementById('chart-bugs-origin-donut');
  const badge = document.getElementById('badge-bugs-origin-filter');
  if (!container) return;

  const categories = { 'Legado': 0, 'GeradoPorUS': 0, '!BUG': 0, 'Geral': 0 };
  let totalBugs = 0;

  bugs.forEach(b => {
    const wiTags = g_data.tagsByWi.get(b.Id) || [];
    const lowerTags = wiTags.map(t => t.toLowerCase());

    let originCat = 'Geral';
    if (lowerTags.includes('legado')) originCat = 'Legado';
    else if (lowerTags.includes('!bug')) originCat = '!BUG';
    else if (lowerTags.includes('geradoporus')) originCat = 'GeradoPorUS';

    categories[originCat]++;
    totalBugs++;
  });

  if (badge) {
    if (g_bugsActiveOriginFilter !== 'all') {
      badge.style.display = 'inline-block';
      badge.textContent = `Origem: ${g_bugsActiveOriginFilter} ×`;
    } else {
      badge.style.display = 'none';
    }
  }

  if (totalBugs === 0) {
    container.innerHTML = `<span class="placeholder-text" style="display: block; text-align: center; padding: 20px 0;">Sem dados de bugs</span>`;
    return;
  }

  const radius = 70;
  const circ = 2 * Math.PI * radius; // ~439.82

  let currentOffset = 0;
  let segments = '';

  const colors = {
    'Legado': 'hsl(215, 90%, 55%)',     // Azul
    'GeradoPorUS': 'var(--color-danger)', // Vermelho
    '!BUG': 'hsl(38, 92%, 50%)',         // Amarelo
    'Geral': 'hsl(142, 40%, 45%)'         // Verde
  };

  let legendHtml = '';

  Object.keys(categories).forEach(cat => {
    const count = categories[cat];
    const col = colors[cat];
    const pct = totalBugs > 0 ? (count / totalBugs) * 100 : 0;

    const dashArrayVal = totalBugs > 0 ? (count / totalBugs) * circ : 0;
    const strokeDash = `${dashArrayVal} ${circ - dashArrayVal}`;
    const strokeOffset = circ - currentOffset;

    const isSelected = g_bugsActiveOriginFilter === cat;
    const isDimmed = g_bugsActiveOriginFilter !== 'all' && g_bugsActiveOriginFilter !== cat;

    let segmentClass = "donut-segment bug-origin-donut-segment";
    if (isSelected) segmentClass += " active";
    if (isDimmed) segmentClass += " inactive";

    const strokeWidth = isSelected ? 20 : 14;
    const opacity = isDimmed ? 0.35 : 1;

    if (count > 0) {
      segments += `
        <circle cx="100" cy="100" r="${radius}" fill="none" stroke="${col}" stroke-width="${strokeWidth}" 
                stroke-dasharray="${strokeDash}" stroke-dashoffset="${strokeOffset}" 
                transform="rotate(-90, 100, 100)" class="${segmentClass}" 
                data-origin="${cat}"
                style="opacity: ${opacity}; cursor: pointer; transition: var(--transition-smooth);"/>
      `;
    }

    currentOffset += dashArrayVal;

    const legendSelected = g_bugsActiveOriginFilter === cat ? 'background-color: hsla(252, 31%, 15%, 0.6); border-radius: 4px; border: 1px solid var(--color-primary);' : '';
    legendHtml += `
      <div class="legend-row bug-origin-legend-row" data-origin="${cat}" style="cursor: pointer; display: flex; align-items: center; justify-content: space-between; gap: 8px; padding: 4px; transition: var(--transition-smooth); margin-bottom: 2px; ${legendSelected}">
        <div style="display: flex; align-items: center; gap: 6px;">
          <span style="width: 10px; height: 10px; border-radius: 50%; background-color: ${col}; display: inline-block;"></span>
          <span style="font-weight: 500; font-size: 0.8rem; color: #fff;">${cat}</span>
        </div>
        <span style="font-size: 0.78rem; color: var(--text-muted);"><strong>${count}</strong> (${pct.toFixed(0)}%)</span>
      </div>
    `;
  });

  container.innerHTML = `
    <div style="display: flex; align-items: center; justify-content: space-between; width: 100%; height: 100%; padding: 10px 15px; box-sizing: border-box; gap: 20px;">
      <div style="position: relative; width: 200px; height: 200px; flex-shrink: 0; display: flex; align-items: center; justify-content: center;">
        <svg width="200" height="200" viewBox="0 0 200 200" style="display: block;">
          ${segments}
          <circle cx="100" cy="100" r="54" fill="var(--bg-main)" stroke="var(--border-color)" stroke-width="1"/>
          <text x="100" y="96" fill="#fff" font-size="24" font-weight="800" text-anchor="middle">${totalBugs}</text>
          <text x="100" y="112" fill="var(--text-muted)" font-size="9" text-anchor="middle" letter-spacing="0.5" style="text-transform: uppercase;">Bugs Coletados</text>
        </svg>
      </div>
      <div style="display: flex; flex-direction: column; justify-content: center; text-align: left; max-height: 240px; overflow-y: auto; padding-right: 5px; flex-grow: 1;">
        ${legendHtml}
      </div>
    </div>
  `;

  container.querySelectorAll('.bug-origin-donut-segment, .bug-origin-legend-row').forEach(el => {
    el.addEventListener('click', (e) => {
      const origin = el.getAttribute('data-origin');
      g_bugsActiveOriginFilter = (g_bugsActiveOriginFilter === origin) ? 'all' : origin;
      renderActivePage();
    });
  });

  if (badge) {
    badge.onclick = () => {
      g_bugsActiveOriginFilter = 'all';
      renderActivePage();
    };
  }
}

