// PDF-1: Horas Dev vs Testando por Tipo de WI (gráfico empilhado)
function renderDevVsTestByType(filteredWIs) {
  const container = document.getElementById('chart-capacity-dev-vs-test');
  if (!container) return;
  container.innerHTML = '';

  const DEV_ACTS = new Set(['Development','CodeAdjustment','CodeReview','Rework','Deployment','DevelopmentTest']);
  const TEST_ACTS = new Set(['Testing','TechnicalValidation']);

  const groups = { 'Bug': {dev:0,test:0,other:0}, 'User Story': {dev:0,test:0,other:0} };

  filteredWIs.forEach(wi => {
    const tipo = wi.Tipo;
    if (!groups[tipo]) return;
    const tasks = g_data.tasksByParent.get(wi.Id) || [];
    tasks.forEach(t => {
      const cw = t.CompletedWork || 0;
      if (cw <= 0) return;
      const act = (t.Activity || '').trim();
      if (DEV_ACTS.has(act)) groups[tipo].dev += cw;
      else if (TEST_ACTS.has(act)) groups[tipo].test += cw;
      else groups[tipo].other += cw;
    });
  });

  const tipos = Object.keys(groups).filter(t => (groups[t].dev + groups[t].test + groups[t].other) > 0);
  if (tipos.length === 0) {
    container.innerHTML = `<span class="placeholder-text">Sem dados de tasks com CompletedWork</span>`;
    return;
  }

  const svgW = 560;
  const svgH = 240;
  const padL = 120;
  const padR = 30;
  const padT = 30;
  const padB = 50;
  const chartW = svgW - padL - padR;
  const chartH = svgH - padT - padB;
  const barW = Math.min(80, chartW / tipos.length * 0.55);
  const gap = chartW / tipos.length;

  const maxVal = Math.max(...tipos.map(t => groups[t].dev + groups[t].test + groups[t].other), 1);

  const COLORS = { dev: 'hsl(210,80%,55%)', test: 'hsl(160,65%,45%)', other: 'hsl(38,80%,55%)' };
  const LABELS = { dev: 'Dev / Código', test: 'Testes / QA', other: 'Outros' };

  let bars = '';
  tipos.forEach((tipo, i) => {
    const g = groups[tipo];
    const total = g.dev + g.test + g.other;
    const cx = padL + i * gap + gap / 2;
    const bx = cx - barW / 2;

    let yOff = padT + chartH;
    [['dev', g.dev], ['test', g.test], ['other', g.other]].forEach(([key, val]) => {
      if (val <= 0) return;
      const h = (val / maxVal) * chartH;
      yOff -= h;
      bars += `<rect x="${bx}" y="${yOff}" width="${barW}" height="${h}" fill="${COLORS[key]}" rx="2" opacity="0.88"/>`;
      if (h > 14) {
        bars += `<text x="${cx}" y="${yOff + h / 2 + 4}" text-anchor="middle" fill="#fff" font-size="10" font-weight="700">${Math.round(val)}h</text>`;
      }
    });

    // Label below bar
    bars += `<text x="${cx}" y="${padT + chartH + 18}" text-anchor="middle" fill="var(--text-main)" font-size="12" font-weight="600">${tipo}</text>`;
    bars += `<text x="${cx}" y="${padT + chartH + 32}" text-anchor="middle" fill="var(--text-muted)" font-size="10">${Math.round(total)}h total</text>`;

    // Ratio dev:test
    if (g.test > 0) {
      const ratio = (g.dev / g.test).toFixed(1);
      bars += `<text x="${cx}" y="${padT - 6}" text-anchor="middle" fill="var(--text-muted)" font-size="9">ratio ${ratio}:1</text>`;
    }
  });

  // Y axis ticks
  let axis = '';
  for (let v = 0; v <= maxVal; v += Math.ceil(maxVal / 4)) {
    const y = padT + chartH - (v / maxVal) * chartH;
    axis += `<line x1="${padL - 4}" y1="${y}" x2="${padL + chartW}" y2="${y}" stroke="var(--border-color)" stroke-dasharray="3 3"/>`;
    axis += `<text x="${padL - 8}" y="${y + 4}" text-anchor="end" fill="var(--text-muted)" font-size="9">${Math.round(v)}h</text>`;
  }

  // Legend
  let legend = '';
  const legendItems = [['dev', COLORS.dev, LABELS.dev], ['test', COLORS.test, LABELS.test], ['other', COLORS.other, LABELS.other]];
  legendItems.forEach(([, color, label], i) => {
    const lx = padL + i * 140;
    legend += `<rect x="${lx}" y="${svgH - 18}" width="12" height="12" fill="${color}" rx="2"/>`;
    legend += `<text x="${lx + 16}" y="${svgH - 7}" fill="var(--text-muted)" font-size="10">${label}</text>`;
  });

  container.innerHTML = `<svg width="100%" viewBox="0 0 ${svgW} ${svgH}">${axis}${bars}${legend}</svg>`;
}

