// MD-2: KPIs de Lead Time até PRR para bugs
function renderBugsPRRMetrics(bugs) {
  const prrMedianEl = document.getElementById('kpi-bug-prr-median');
  const prrCoverageEl = document.getElementById('kpi-bug-prr-coverage');
  if (!prrMedianEl || !prrCoverageEl) return;

  const leadTimes = [];
  let bugsWithPRR = 0;
  let bugsResolved = 0;

  const today = new Date(TODAY_ANCHOR);
  // Get filter date range globally
  const dateRange = document.getElementById('filter-date-range')?.value || 'last-30';
  let startDateMs = 0;
  let endDateMs = today.getTime();

  if (dateRange !== 'all') {
    if (dateRange === 'today') {
      startDateMs = new Date(today.getFullYear(), today.getMonth(), today.getDate()).getTime();
    } else if (dateRange === 'this-year') {
      startDateMs = new Date(today.getFullYear(), 0, 1).getTime();
    } else if (dateRange === 'last-year') {
      startDateMs = new Date(today.getFullYear() - 1, 0, 1).getTime();
      endDateMs = new Date(today.getFullYear() - 1, 11, 31, 23, 59, 59).getTime();
    } else {
      const days = parseInt(dateRange.replace('last-', ''), 10) || 30;
      startDateMs = today.getTime() - (days * 24 * 60 * 60 * 1000);
    }
  }

  bugs.forEach(b => {
    if (b.State === 'Closed' || b.BoardColumn === 'Concluído') {
      const resolvedDate = new Date(b.DataFechamento || b.DataModificacao).getTime();
      // Only include bugs resolved in the filter window
      if (dateRange === 'all' || (resolvedDate >= startDateMs && resolvedDate <= endDateMs)) {
        bugsResolved++;

        // Find if bug reached PRR (Pronto para Release)
        const visits = g_data.tempoColunaByWi.get(b.Id) || [];
        const prrVisit = visits.find(v => v.BoardColumn === 'Pronto pra Release');

        if (prrVisit) {
          bugsWithPRR++;
          const cDate = new Date(b.DataCriacao).getTime();
          const prrDate = new Date(prrVisit.DataEntrada).getTime();
          leadTimes.push((prrDate - cDate) / (1000 * 3600 * 24));
        }
      }
    }
  });

  if (leadTimes.length > 0) {
    leadTimes.sort((a, b) => a - b);
    const mid = Math.floor(leadTimes.length / 2);
    const median = leadTimes.length % 2 !== 0 ? leadTimes[mid] : (leadTimes[mid - 1] + leadTimes[mid]) / 2;
    prrMedianEl.textContent = `${median.toFixed(1)} d`;
  } else {
    prrMedianEl.textContent = '-';
  }

  const coveragePct = bugsResolved > 0 ? Math.round((bugsWithPRR / bugsResolved) * 100) : 0;
  prrCoverageEl.textContent = bugsResolved > 0 ? `${bugsWithPRR}/${bugsResolved} (${coveragePct}%)` : '-';
}

  const leadTimes = [];
  let withPRR = 0;

  bugs.forEach(b => {
    const visits = (g_data.tempoColunaByWi.get(b.Id) || []).filter(v => v.BoardColumn === 'Pronto pra Release');
    if (visits.length > 0 && visits[0].UltimaEntrada && b.DataCriacao) {
      const h = (new Date(visits[0].UltimaEntrada) - new Date(b.DataCriacao)) / 3600000;
      if (h >= 0) {
        leadTimes.push(h);
        withPRR++;
      }
    }
  });

  if (leadTimes.length > 0) {
    leadTimes.sort((a, b) => a - b);
    const median = leadTimes[Math.floor(leadTimes.length / 2)];
    const medStr = median < 24 ? `${median.toFixed(1)} h` : `${(median / 24).toFixed(1)} d`;
    prrMedianEl.textContent = medStr;
  } else {
    prrMedianEl.textContent = '-';
  }

  const total = bugs.length;
  const pct = total > 0 ? Math.round(withPRR / total * 100) : 0;
  prrCoverageEl.textContent = `${withPRR}/${total} (${pct}%)`;
}

