  </div>`;
});
legendHtml += `</div>`;

container.innerHTML = `
  <div style="position: relative; width: 100%; display: flex; flex-direction: column; align-items: flex-start; padding-top: 20px;">
    <svg width="100%" viewBox="0 0 ${width} ${height}" style="max-width: 1200px; overflow: visible;">
      ${axisHtml}
      ${barsHtml}
    </svg>
    ${legendHtml}
  </div>
`;

